def flip_case(string: str) -> str:
    """ For a given string, flip lowercase characters to uppercase and uppercase to lowercase.
    >>> flip_case('Hello')
    'hELLO'
    """

Output:
    if string.isupper():
        return string.lower()
    else:
        return string.upper()

# Usage example
string = 'Hello'
print(flip_case(string)) # Outputs: hELLO
