def fizz_buzz(n: int):
    """Return the number of times the digit 7 appears in integers less than n which are divisible by 11 or 13.
    >>> fizz_buzz(50)
    0
    >>> fizz_buzz(78)
    2
    >>> fizz_buzz(79)
    3
    """

Output:
    def fizz_buzz(n: int):
        if n == 0:
            return 0
        if n == 1:
            return 1

        result = 0
        for i in range(1, n):
            if is_divisible_by_11(i):
                result += digit_7(i)
        return result

    def is_divisible_by_11(n):
        # Base case
        if n == 0:
            return False

        # Recursive case
        if n % 10 == 0:
            return True
        else:
            last_digit = n % 10
            next_digit = n // 10
            if is_divisible_by_11(next_digit) and (last_digit + 7) % 10 == 0:
                return True
            else:
                return False

    def digit_7(n):
        result = 0
        while n > 0:
            remainder = n % 10
            if remainder == 7:
                result += 1
            n //= 10
        return result
